+}
+
+#[derive(Debug, serde::Deserialize)]
+#[serde(rename_all = "camelCase")]
+struct GoogleChatMessage {
+    text: Option<String>,
+    argument_text: Option<String>,
+    sender: Option<GoogleChatUser>,
+}
+
+#[derive(Debug, serde::Deserialize)]
+#[serde(rename_all = "camelCase")]
+struct GoogleChatSpace {
+    name: Option<String>,
